        left = 0
        res = 0
        for right in range(len(s)):
            if s[right] == 'a':
                count[0] += 1
            elif s[right] == 'b':
                count[1] += 1
            else:
                count[2] += 1
            while min(count) > 0:
                if s[left] == 'a':
                    count[0] -= 1
                elif s[left] == 'b':
                    count[1] -= 1
                else:
                    count[2] -= 1
                left += 1
            res += len(s) - right
        return res

