#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int numberOfSubstrings(string s) {
        int count[3] = {0};
        int left = 0;
        int res = 0;
        for (int right = 0; right < s.size(); right++) {
            if (s[right] == 'a') {
                count[0]++;
            } else if (s[right] == 'b') {
                count[1]++;
            } else {
                count[2]++;
            }
            while (*min_element(count, count + 3) > 0) {
                if (s[left] == 'a') {
                    count[0]--;
                } else if (s[left] == 'b') {
                    count[1]--;
                } else {
                    count[2]--;
                }
                left++;
            }
            res += s.size() - right;
        }
        return res;
    }
};

